) -> str:
    lines = [
        "# Agent Fox Technical Core V1A-0 — Live Baseline Audit",
        "",
        f"- Mission: `{MISSION_ID}`",
        f"- Root: `{root}`",
        f"- Generated: `{utc_now()}`",
